@prefix ada: <https://ada.astromat.org/metadata/> .
@prefix schema: <https://schema.org/> .
@prefix schema1: <http://schema.org/> .
@prefix sh: <http://www.w3.org/ns/shacl#> .
@prefix xsd: <http://www.w3.org/2001/XMLSchema#> .

[] a sh:ValidationReport ;
    sh:conforms false ;
    sh:result [ a sh:ValidationResult ;
            sh:focusNode [ a ada:collection,
                        schema:Collection ;
                    ada:componentType [ a ada:SEMEDSElementalMaps ] ;
                    ada:filelist [ schema1:encodingFormat "image/tiff" ;
                            ada:componentType "ada:SEMEDSElementalMap" ;
                            ada:fileName "map_Si_Ka.tif" ],
                        [ schema1:encodingFormat "image/tiff" ;
                            ada:componentType "ada:SEMEDSElementalMap" ;
                            ada:fileName "map_Fe_Ka.tif" ] ;
                    ada:memberTypes "ada:SEMEDSElementalMap" ;
                    ada:nFiles 5 ] ;
            sh:resultMessage "Collection should specify componentType." ;
            sh:resultPath ada:componentType ;
            sh:resultSeverity sh:Warning ;
            sh:sourceConstraintComponent sh:DatatypeConstraintComponent ;
            sh:sourceShape [ sh:datatype xsd:string ;
                    sh:message "Collection should specify componentType." ;
                    sh:path ada:componentType ;
                    sh:severity sh:Warning ] ;
            sh:value [ a ada:SEMEDSElementalMaps ] ] .

@prefix sh: <http://www.w3.org/ns/shacl#> .
@prefix xsd: <http://www.w3.org/2001/XMLSchema#> .

[] a sh:ValidationReport ;
    sh:conforms true .
